INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('招聘项目助理实习生 - 长沙', '人力资源服务 / 咨询', '长沙', '外资企业', 100, 150, '1. 熟练使用 Office 办公软件，可完成校招 / 社招项目的基础文档整理、数据统计工作；2. 掌握简历筛选、电话沟通的基础技能，可独立完成候选人初步意向沟通；3. 具备校招项目基础执行能力，可完成宣讲会、双选会的落地支持工作。', '1. 普通话标准，具备良好的沟通表达能力；2. 认真细致，有极强的责任心；3. 学习能力强，可快速掌握招聘项目的执行流程与规范；4. 有良好的服务意识与团队协作能力，接受零基础实习。', 1, '极度友好', '1. 校招相关：发布就业网、联系院校老师和学生、宣讲现场支持等；2. 社招相关：简历搜索、电话意向沟通、笔面试现场签到引领等；3. 领导安排的其他工作。', '校招项目运营, 候选人寻访 /mapping, 招聘全流程执行, 简历筛选与面试', '本科及以上', '专业不限，接受大一 / 大二在校生投递', '在校学生均可投递，保证 3 天 / 周的出勤，实习满 2 个月', '日常实习', '人力资源管理师相关证书优先、有校园社团 / 校招项目经验优先、有招聘相关实习经验优先', '100-150 / 天', '46106', '46305', 'https://www.shixiseng.com/intern/inn_gu0wqfe79ewm?pcm=pc_SearchList', '招聘类 (含招聘专员 / 助理 / 校招专员)', '乙方（人力资源服务商 / 猎头 / 咨询公司）'), ('HR 招聘实习生 - 上海', '互联网 / IT', '上海', '上市公司', 120, 150, '1. 熟练操作主流招聘渠道，可独立完成招聘渠道的维护与拓展；2. 掌握简历开源、筛选与面试邀约技能，可独立完成候选人初步沟通与面试安排；3. 可熟练使用办公软件，具备较好的数据分析能力，可完成招聘数据统计与整理；4. 掌握招聘全流程操作规范，可独立跟进面试全流程与反馈。', '1. 具备良好的沟通能力，抗压能力、自驱力强，具备良好的执行力；2. 学习能力强，可快速适应互联网行业的招聘节奏；3. 结果导向，目标感强，可主动推进招聘流程落地；4. 责任心强，有良好的团队协作意识与服务意识。', 1, '友好', '1. 维护和拓展公司招聘渠道，协助各类招聘活动；2. 根据岗位需求进行简历开源、候选人沟通、邀约面试、面试接待等日常招聘工作；3. 负责跟进面试安排、面试反馈等招聘整体流程；4. 配合公司其他各项工作的开展。', '招聘全流程执行, 候选人寻访 /mapping, 简历筛选与面试, 渠道拓展与运营', '本科及以上', '专业不限', '实习至少 2 个月，能够全勤、尽快入职者优先，在校本科生可投', '日常实习', '人力资源管理师相关证书优先、有互联网大厂招聘实习经验优先、有校园招聘项目运营经验优先', '120-150 / 天', '46106', '46112', 'https://www.shixiseng.com/intern/inn_losd3ycptuz9?pcm=pc_SearchList', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）'), ('招聘专员 - 上海（实习可转正）', '互联网 / IT', '上海', '民营企业', 150, 200, '1. 熟练掌握招聘全流程操作规范，可独立完成从需求对接至 offer 跟进的全闭环工作；2. 具备招聘平台运营与维护能力，可独立完成简历初筛、面试邀约全流程；3. 具备招聘数据统计与分析能力，可基于招聘效果输出优化建议；4. 熟悉人力资源管理理论和相关法律法规，可合规开展招聘工作；5. 具备优秀的问题分析与解决能力，可快速应对招聘过程中的各类问题。', '1. 具备良好的沟通能力和团队合作精神，能够与不同层面的人员进行有效沟通；2. 有较强的组织和协调能力，能够高效地处理多项任务；3. 对人力资源工作有热情，具有良好的职业道德和责任心；4. 学习能力强，可快速理解人工智能行业的业务需求与岗位特点；5. 抗压能力强，可适应快节奏的工作环境。', 1, '友好', '1. 与业务部门紧密合作，了解业务需求和目标，提供专业的招聘建议和解决方案；2. 招聘平台的日常运营与维护，负责简历的初筛，与候选人进行线上沟通以及面试邀约；3. 与业务负责人协调面试时间，安排面试，并对候选人的面试结果进行后续的追踪；4. 建立和维护良好的候选人关系，提供优质的招聘体验；5. 跟踪招聘效果，分析数据并提供反馈，不断改进招聘策略。', '招聘全流程执行, 渠道拓展与运营, 简历筛选与面试, 招聘流程优化, 招聘数据分析', '本科及以上', '人力资源或相关专业优先', '至少 1 年以上招聘经验优先，优秀应届生可放宽', '日常实习', '人力资源管理师相关证书优先、有 AI / 互联网行业招聘经验优先、有校园招聘项目运营经验优先', '150-200 / 天', '46107', '46150', 'https://www.shixiseng.com/intern/inn_afh6uiw20cnz?pcm=pc_SearchList', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）'), ('HR Intern 人力资源实习生-上海', '制造', '上海', '外资企业', 150, 200, '1. 精通英语，尤其是书面英语读写能力 2. 熟练使用 Microsoft Office 办公软件（Word、Excel、PowerPoint） 3. 具备基础的文档处理、物料制作能力', '1. 注重细节，责任心强，乐于学习 2. 具备良好的沟通表达能力 3. 能够谨慎处理敏感信息与机密内容，具备良好的保密意识 4. 具备良好的执行力与多任务处理能力', 1, '极度友好', '1. 协助编制 2025 年弹性工作时间申请清单及相关材料 2. 确认 Spot 获奖员工名单，制作海报，每月分发员工礼品 3. 协助组织人事档案室的日常管理工作 4. 支持培训相关的款项支付流程 5. 负责培训活动的前期准备与现场执行支持 6. 组织并重新整理标记办公室图书角 7. 负责导师计划培训项目的前期准备与现场支持 8. 协助筹备各类员工活动，包括人才午餐、高管拜访、销售网络研讨会等 9. 支持公司年会的筹备相关工作', '员工关系支持', '本科及以上', '人力资源管理、工商管理等管理类相关专业优先，无强制专业限制', '在校大学生，可稳定实习 5 个月，每周到岗 3 天，有人力资源相关实习经验优先', '日常实习', '1. 有外企 HR 相关实习经验 2. 持有英语四六级 / 专四专八证书 3. 有校园 / 企业活动组织经验', '150-200 元 / 天', '46099', '46437', 'https://www.shixiseng.com/intern/inn_4zfhp1qlwnja?pcm=pc_SearchList', '员工关系类', '甲方（企业自有 HR 岗）'), ('招聘专员 - 深圳（校招）', '互联网 / IT', '深圳', '民营企业', 5000, 10000, '1. 熟练掌握主流招聘渠道的使用、拓展与运营方法；2. 具备招聘需求分析能力，可配合制定候选人寻访策略；3. 掌握候选人简历筛选、初轮面试评估技能，可独立完成候选人报告撰写；4. 具备候选人全流程寻访、沟通与跟进能力；5. 可根据招聘反馈与数据，调整招聘方向，优化招聘动作', '1. 普通话标准，亲和力强，逻辑思维清晰，具备优秀的沟通表达与协调能力；2. 结果导向，目标感强，可独立推进招聘流程完成交付目标；3. 责任心强，学习能力强，可快速适配业务端的招聘需求；4. 具备良好的问题解决能力，可根据反馈快速调整工作策略', 1, '友好', '1. 负责公司招聘职位的完成；2. 分析职位需求，讨论形成寻访策略；3. 根据既定方向，进行寻访渠道的分析、拓展，整合候选人资源，定位目标候选人；4. 按照职位的要求，与候选人进行沟通和评估，制作并提交候选人报告；5. 及时了解业务对候选人的反馈，不断调整方向，保证招聘职位完成率。', '招聘全流程执行, 候选人寻访 /mapping, 简历筛选与面试, 渠道拓展与运营, 招聘数据分析', '本科及以上', '无明确限制，人力资源管理相关专业优先', '有招聘、猎头类相关实习工作经验优先', '应届生校招', '人力资源管理师相关证书优先、有校园招聘项目运营经验优先', '5k-10k / 月', '46103', NULL, 'https://www.shixiseng.com/intern/inn_ev3kzx3ugh6o?pcm=pc_SearchList', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）');